+async fn fcp_host_binary_fixture_matrix_surfaces_discovery_and_introspection_metadata()
+-> Result<(), Box<dyn std::error::Error>> {
+    let host = HttpHostProcess::spawn(
+        HOST_INTEGRATION_FIXTURES
+            .iter()
+            .copied()
+            .map(matrix_fixture_config)
